messages.content:
Generate a domino run concept.

Locked values (do not change):
  domino_count: 300
  domino_width: 0.08
  domino_height: 0.4
  domino_depth: 0.06
  spacing_ratio: 0.35
  path_amplitude: 1.0
  path_cycles: 2.0
  domino_mass: 0.3
  domino_friction: 0.6
  domino_bounce: 0.1
  trigger_impulse: 1.5
  trigger_tilt_degrees: 8.0
  duration_sec: 65

Archetype for this video: branching
Palette for this video: neon

Output ONLY valid JSON matching this schema:
{
  "$defs": {
    "AudioBrief": {
      "description": "Audio requirements extracted from concept brief.",
      "properties": {
        "mood": {
          "description": "Mood tags for music selection, e.g. ['upbeat', 'energetic']",
          "items": {
            "type": "string"
          },
          "title": "Mood",
          "type": "array"
        },
        "tempo_bpm_min": {
          "default": 90,
          "description": "Minimum BPM for track selection",
          "title": "Tempo Bpm Min",
          "type": "integer"
        },
        "tempo_bpm_max": {
          "default": 140,
          "description": "Maximum BPM for track selection",
          "title": "Tempo Bpm Max",
          "type": "integer"
        },
        "energy_curve": {
          "$ref": "#/$defs/EnergyLevel",
          "default": "building",
          "description": "Overall energy progression of the video"
        }
      },
      "required": [
        "mood"
      ],
      "title": "AudioBrief",
      "type": "object"
    },
    "DominoArchetype": {
      "description": "Archetype categories for the Blender domino run pipeline.",
      "enum": [
        "spiral",
        "s_curve",
        "branching",
        "word_spell",
        "cascade"
      ],
      "title": "DominoArchetype",
      "type": "string"
    },
    "EnergyLevel": {
      "description": "Energy curve descriptor for audio/visual matching.",
      "enum": [
        "low",
        "building",
        "high",
        "climax"
      ],
      "title": "EnergyLevel",
      "type": "string"
    }
  },
  "description": "Full configuration for generating one domino run in Blender.\n\nProduced by the idea agent (LLM) and consumed by the Blender scripts.\nThe LLM only controls creative parameters (path shape, count, colours,\nfinale object). Physics values are research-locked for reliable toppling.",
  "properties": {
    "seed": {
      "description": "Random seed for deterministic generation",
      "title": "Seed",
      "type": "integer"
    },
    "archetype": {
      "$ref": "#/$defs/DominoArchetype",
      "description": "Path archetype to use"
    },
    "title": {
      "description": "Short descriptive title for the concept",
      "title": "Title",
      "type": "string"
    },
    "visual_brief": {
      "description": "2-3 sentence description of what the viewer sees",
      "title": "Visual Brief",
      "type": "string"
    },
    "domino_count": {
      "default": 300,
      "description": "Number of dominoes to place along the path",
      "maximum": 1000,
      "minimum": 50,
      "title": "Domino Count",
      "type": "integer"
    },
    "path_amplitude": {
      "default": 1.0,
      "description": "Horizontal amplitude for curved paths (Blender units)",
      "maximum": 5.0,
      "minimum": 0.0,
      "title": "Path Amplitude",
      "type": "number"
    },
    "path_cycles": {
      "default": 1.0,
      "description": "Number of S-curve oscillation cycles",
      "maximum": 4.0,
      "minimum": 0.5,
      "title": "Path Cycles",
      "type": "number"
    },
    "spiral_turns": {
      "default": 2.0,
      "description": "Number of spiral rotations (spiral archetype only)",
      "maximum": 5.0,
      "minimum": 1.0,
      "title": "Spiral Turns",
      "type": "number"
    },
    "branch_count": {
      "default": 3,
      "description": "Number of branches (branching archetype only)",
      "maximum": 5,
      "minimum": 2,
      "title": "Branch Count",
      "type": "integer"
    },
    "domino_width": {
      "default": 0.08,
      "description": "Domino width (m)",
      "title": "Domino Width",
      "type": "number"
    },
    "domino_height": {
      "default": 0.4,
      "description": "Domino height (m)",
      "title": "Domino Height",
      "type": "number"
    },
    "domino_depth": {
      "default": 0.06,
      "description": "Domino depth / thickness in tipping direction (m)",
      "title": "Domino Depth",
      "type": "number"
    },
    "spacing_ratio": {
      "default": 0.35,
      "description": "Spacing between dominoes as fraction of domino height",
      "maximum": 0.6,
      "minimum": 0.2,
      "title": "Spacing Ratio",
      "type": "number"
    },
    "trigger_frame": {
      "default": 30,
      "description": "Frame at which the trigger animation fires",
      "maximum": 150,
      "minimum": 5,
      "title": "Trigger Frame",
      "type": "integer"
    },
    "trigger_impulse": {
      "default": 1.5,
      "description": "Force applied to tip the first domino",
      "maximum": 5.0,
      "minimum": 0.5,
      "title": "Trigger Impulse",
      "type": "number"
    },
    "trigger_tilt_degrees": {
      "default": 8.0,
      "description": "Tilt angle for first domino to initiate chain",
      "maximum": 20.0,
      "minimum": 3.0,
      "title": "Trigger Tilt Degrees",
      "type": "number"
    },
    "finale_type": {
      "default": "none",
      "description": "Finale object at end of path: none, tower, ramp, ball",
      "title": "Finale Type",
      "type": "string"
    },
    "palette": {
      "default": "rainbow",
      "description": "Colour palette name",
      "title": "Palette",
      "type": "string"
    },
    "camera_style": {
      "default": "tracking",
      "description": "Camera style",
      "title": "Camera Style",
      "type": "string"
    },
    "lighting_preset": {
      "default": "studio",
      "description": "Lighting preset",
      "title": "Lighting Preset",
      "type": "string"
    },
    "duration_sec": {
      "default": 65,
      "maximum": 68,
      "minimum": 62,
      "title": "Duration Sec",
      "type": "integer"
    },
    "fps": {
      "default": 30,
      "maximum": 30,
      "minimum": 24,
      "title": "Fps",
      "type": "integer"
    },
    "domino_mass": {
      "default": 0.3,
      "description": "Domino mass (kg)",
      "title": "Domino Mass",
      "type": "number"
    },
    "domino_friction": {
      "default": 0.6,
      "maximum": 0.9,
      "minimum": 0.4,
      "title": "Domino Friction",
      "type": "number"
    },
    "domino_bounce": {
      "default": 0.1,
      "maximum": 0.3,
      "minimum": 0.0,
      "title": "Domino Bounce",
      "type": "number"
    },
    "ground_friction": {
      "default": 0.8,
      "maximum": 1.0,
      "minimum": 0.6,
      "title": "Ground Friction",
      "type": "number"
    },
    "substeps_per_frame": {
      "default": 20,
      "maximum": 30,
      "minimum": 10,
      "title": "Substeps Per Frame",
      "type": "integer"
    },
    "solver_iterations": {
      "default": 20,
      "maximum": 60,
      "minimum": 10,
      "title": "Solver Iterations",
      "type": "integer"
    },
    "hook_text": {
      "default": "",
      "description": "Hook caption text (<=6 words) shown at 0-2s",
      "maxLength": 50,
      "title": "Hook Text",
      "type": "string"
    },
    "audio_brief": {
      "$ref": "#/$defs/AudioBrief"
    },
    "novelty_score": {
      "default": 7.0,
      "maximum": 10.0,
      "minimum": 0.0,
      "title": "Novelty Score",
      "type": "number"
    },
    "feasibility_score": {
      "default": 9.0,
      "maximum": 10.0,
      "minimum": 0.0,
      "title": "Feasibility Score",
      "type": "number"
    }
  },
  "required": [
    "seed",
    "archetype",
    "title",
    "visual_brief"
  ],
  "title": "DominoCourseConfig",
  "type": "object"
}
